 862→### E2E Smoke Test (erweitere bestehende Smoke-Tests)
 863→
 864→Der Smoke Test nutzt direkte DB-/Repository-Calls, keine rohen HTTP-Requests.
 865→
 866→```ts
 867→// === PLUGGABLE OUTPUT SMOKE — Happy Path ===
 868→
 869→// 1. Conversation importieren und Artefakte generieren
 870→const conversation = createTestConversation();
 871→const artifacts = buildArtifacts(conversation);
 872→
 873→// 2. Alle 3 Server-Artefakte vorhanden
 874→assert(artifacts.markdown, "markdown-Artefakt existiert");
 875→assert(artifacts.handover, "handover-Artefakt existiert");
 876→assert(artifacts.json, "json-Artefakt existiert");
 877→
 878→// 3. Export-Endpoint für alle Formate
 879→for (const format of ["markdown", "handover", "json"]) {
 880→  const exported = exportArtifact({ importId: testId, format });
 881→  assert(exported.length > 0, `${format} Export nicht leer`);
 882→}
 883→
 884→// 4. Registry-Konsistenz
 885→const sharedFormats = defaultRegistry.getAll().map(f => f.id);
 886→assert(sharedFormats.includes("reader"), "reader in shared Registry");
 887→assert(sharedFormats.includes("markdown"), "markdown in shared Registry");
 888→assert(sharedFormats.includes("handover"), "handover in shared Registry");
 889→assert(sharedFormats.includes("json"), "json in shared Registry");
 890→assert(sharedFormats.includes("html"), "html in shared Registry (Schritt 13)");
 891→
 892→// 5. Client-Plugin-Registry
 893→const clientFormats = clientFormatRegistry.getAll().map(p => p.descriptor.id);
 894→assert(clientFormats.length === 5, "5 Client-Plugins registriert");
 895→
 896→// 6. Adjustable-Formats korrekt
 897→const adjustable = defaultRegistry.getAdjustable().map(f => f.id);
 898→assert(adjustable.includes("reader"), "reader ist adjustable");
 899→assert(adjustable.includes("markdown"), "markdown ist adjustable");
 900→assert(!adjustable.includes("json"), "json ist nicht adjustable");
 901→
 902→// === PLUGGABLE OUTPUT SMOKE — Fehlerfälle ===
 903→
 904→// 7. Unbekanntes Format → Fehler
 905→try {
 906→  exportArtifact({ importId: testId, format: "nonexistent" });
 907→  assert(false, "Sollte NOT_FOUND werfen");
 908→} catch (e) {
 909→  assert(e instanceof Error, "Wirft Error-Instanz");
 910→}
 911→
 912→// 8. Entfernte Enum-Werte → Zod-Validierung schlägt fehl
 913→try {
 914→  adjustmentTargetFormatSchema.parse("html_legacy");
 915→  assert(false, "Sollte Zod-Error werfen");
 916→} catch (e) {
 917→  assert(e instanceof z.ZodError, "Wirft ZodError");
 918→}
 919→
 920→// 9. Doppelte Format-Registrierung → Error
 921→try {
 922→  const reg = new FormatRegistry();
 923→  reg.register(BUILTIN_FORMATS[0]);
 924→  reg.register(BUILTIN_FORMATS[0]); // Duplikat
 925→  assert(false, "Sollte bei Duplikat werfen");
 926→} catch (e) {
 927→  assert(e instanceof Error, "Wirft Error bei Duplikat");
 928→}
 929→```
 930→
 931→> **Checkliste für E2E-Tests:**
 932→> - [ ] Vollständiger Happy-Path: Import → Artefakte → Export → Registry-Konsistenz
 933→> - [ ] 3 Fehlerfälle: unbekanntes Format, entfernter Enum-Wert, Duplikat-Registrierung
 934→> - [ ] Seiteneffekt-Freiheit: Bestehende Conversation-Daten unverändert nach allen Operationen
 935→> - [ ] Cleanup: Testdaten am Ende aufräumen
