**Verhaltens-Test** (`packages/shared/src/__tests__/adjustments-schema-cleanup.test.ts`):

```ts
describe("adjustmentTargetFormatSchema nach Bereinigung", () => {
  test("akzeptiert die 4 aktiven Formate", () => {
    for (const format of ["reader", "markdown", "handover", "json"]) {
      expect(adjustmentTargetFormatSchema.parse(format)).toBe(format);
    }
