- [ ] `defaultRegistry` ist mit allen 4 Built-in Formaten initialisiert

**Strukturelle Prüfung:**

```ts
// Dieser Code muss kompilieren ohne Fehler:
import {
  type OutputFormatDescriptor,
  BUILTIN_FORMATS,
  FormatRegistry,
  defaultRegistry,
} from "@chat-exporter/shared";

// Interface prüfen
const desc: OutputFormatDescriptor = {
  id: "test",
  label: "Test",
  adjustable: false,
  supportedRuleKinds: [],
  exportMimeType: "text/plain",
  exportExtension: ".txt",
};

// Registry-API prüfen
