**Verhaltens-Test** (`packages/shared/src/__tests__/output-formats.test.ts`):

```ts
describe("OutputFormatDescriptor + BUILTIN_FORMATS", () => {
  test("BUILTIN_FORMATS enthält genau 4 Formate", () => {
    expect(BUILTIN_FORMATS).toHaveLength(4);
  });

  test("alle IDs sind unique", () => {
    const ids = BUILTIN_FORMATS.map((f) => f.id);
    expect(new Set(ids).size).toBe(ids.length);
  });

  test("reader und markdown sind adjustable", () => {
    const reader = BUILTIN_FORMATS.find((f) => f.id === "reader");
    const markdown = BUILTIN_FORMATS.find((f) => f.id === "markdown");
    expect(reader?.adjustable).toBe(true);
    expect(markdown?.adjustable).toBe(true);
  });

  test("handover und json sind nicht adjustable", () => {
    const handover = BUILTIN_FORMATS.find((f) => f.id === "handover");
    const json = BUILTIN_FORMATS.find((f) => f.id === "json");
    expect(handover?.adjustable).toBe(false);
    expect(json?.adjustable).toBe(false);
  });

  test("adjustable Formate enthalten custom_style in supportedRuleKinds", () => {
    for (const f of BUILTIN_FORMATS.filter((f) => f.adjustable)) {
      expect(f.supportedRuleKinds).toContain("custom_style");
    }
  });

  test("alle supportedRuleKinds existieren in ruleEffectSchema", () => {
    // Prüfe dass keine erfundenen Effect-Types deklariert werden
    const validKinds = [
      "adjust_block_spacing",
      "increase_heading_emphasis",
      "refine_selected_block_presentation",
      "bold_prefix_before_colon",
      "render_markdown_strong",
      "promote_to_heading",
      "normalize_list_structure",
      "normalize_markdown_table",
      "reshape_markdown_block",
      "custom_style",
    ];
    for (const f of BUILTIN_FORMATS) {
      for (const kind of f.supportedRuleKinds) {
        expect(validKinds).toContain(kind);
      }
    }
  });
});

describe("FormatRegistry", () => {
  test("register() und get() funktionieren", () => {
    const reg = new FormatRegistry();
    const desc = { id: "test", label: "Test", adjustable: false, supportedRuleKinds: [], exportMimeType: "text/plain", exportExtension: ".txt" };
    reg.register(desc);
    expect(reg.get("test")).toEqual(desc);
  });

  test("doppelte IDs werfen Error", () => {
    const reg = new FormatRegistry();
    const desc = { id: "test", label: "Test", adjustable: false, supportedRuleKinds: [], exportMimeType: "text/plain", exportExtension: ".txt" };
    reg.register(desc);
    expect(() => reg.register(desc)).toThrow();
  });

  test("getAdjustable() liefert nur adjustable Formate", () => {
    const reg = new FormatRegistry();
    reg.register({ id: "a", label: "A", adjustable: true, supportedRuleKinds: ["custom_style"], exportMimeType: "text/plain", exportExtension: ".txt" });
    reg.register({ id: "b", label: "B", adjustable: false, supportedRuleKinds: [], exportMimeType: "text/plain", exportExtension: ".txt" });
    expect(reg.getAdjustable().map((f) => f.id)).toEqual(["a"]);
  });

  test("supportsRuleKind() prüft korrekt", () => {
    const reg = new FormatRegistry();
    reg.register({ id: "x", label: "X", adjustable: true, supportedRuleKinds: ["custom_style"], exportMimeType: "text/plain", exportExtension: ".txt" });
    expect(reg.supportsRuleKind("x", "custom_style")).toBe(true);
    expect(reg.supportsRuleKind("x", "unknown")).toBe(false);
  });

  test("supportsRuleKind() für unbekanntes Format → false", () => {
    const reg = new FormatRegistry();
    expect(reg.supportsRuleKind("nonexistent", "custom_style")).toBe(false);
  });

  test("defaultRegistry enthält alle 4 Built-in Formate", () => {
    expect(defaultRegistry.getAll()).toHaveLength(4);
    expect(defaultRegistry.get("reader")).toBeDefined();
    expect(defaultRegistry.get("markdown")).toBeDefined();
    expect(defaultRegistry.get("handover")).toBeDefined();
    expect(defaultRegistry.get("json")).toBeDefined();
  });
});
