 33→
 34→export function resolveReaderBlockEffects(
 35→  rules: FormatRule[],
 36→  messageId: string,
 37→  blockIndex: number,
 38→  blockType: Block["type"],
 39→  blockText: string,
 40→  context?: ReaderMatchContext,
 41→) {
 42→  return rules
 43→    .filter(
 44→      (rule) =>
 45→        rule.status === "active" &&
 46→        matchesReaderRule(
 47→          rule,
 48→          messageId,
 49→          blockIndex,
 50→          blockType,
 51→          blockText,
 52→          context,
 53→        ),
 54→    )
 55→    .map((rule) => rule.compiledRule)
 56→    .filter((effect): effect is RuleEffect => effect !== undefined)
 57→    .map(normalizeLegacyEffect);
 58→}
 59→
 60→export function buildReaderEffectsMap(
 61→  rules: FormatRule[],
 62→  conversation: Conversation,
 63→): Map<string, RuleEffect[]> {
 64→  const activeRules = rules.filter((r) => r.status === "active");
 65→  const effectsMap = new Map<string, RuleEffect[]>();
 66→
 67→  for (const message of conversation.messages) {
 68→    const context: ReaderMatchContext = {
 69→      messageRole: message.role,
 70→      blocks: message.blocks,
 71→    };
 72→
 73→    for (
 74→      let blockIndex = 0;
 75→      blockIndex < message.blocks.length;
 76→      blockIndex += 1
 77→    ) {
 78→      const block = message.blocks[blockIndex];
 79→
 80→      if (!block) {
 81→        continue;
 82→      }
 83→
 84→      const effects = activeRules
 85→        .filter((rule) =>
 86→          matchesReaderRule(
 87→            rule,
 88→            message.id,
 89→            blockIndex,
 90→            block.type,
 91→            blockToPlainText(block),
 92→            context,
 93→          ),
 94→        )
 95→        .map((rule) => rule.compiledRule)
 96→        .filter((effect): effect is RuleEffect => effect !== undefined)
 97→        .map(normalizeLegacyEffect);
 98→
 99→      if (effects.length > 0) {
100→        effectsMap.set(`${message.id}:${blockIndex}`, effects);
101→      }
102→    }
103→  }
104→
105→  return effectsMap;
106→}
107→
108→export function applyMarkdownRules(content: string, rules: FormatRule[]) {
109→  const lines = content.split("\n");
110→  const nextLines = [...lines];
111→
112→  for (const rule of rules) {
113→    if (rule.status !== "active") {
114→      continue;
115→    }
116→
117→    const parsedSelector = ruleSelectorSchema.safeParse(rule.selector);
118→    const parsedEffect = ruleEffectSchema.safeParse(rule.compiledRule);
119→
120→    if (!parsedSelector.success || !parsedEffect.success) {
121→      continue;
122→    }
123→
124→    const selector = parsedSelector.data;
125→    const effect = normalizeLegacyEffect(parsedEffect.data);
126→
127→    const strategy = "strategy" in selector ? selector.strategy : undefined;
128→
129→    if (strategy === "compound") {
130→      const transform = effect.markdownTransform;
131→      if (!transform) continue;
132→
133→      // Compound in Markdown: textPattern match on each line
134→      // blockType/messageRole/context not relevant for Markdown (line-based only)
135→      const textPattern =
136→        "textPattern" in selector ? selector.textPattern : null;
137→
138→      for (let index = 0; index < nextLines.length; index += 1) {
139→        const line = nextLines[index] ?? "";
140→
141→        // If textPattern set: only transform matching lines
142→        if (textPattern) {
143→          try {
144→            if (!new RegExp(textPattern).test(line)) continue;
145→          } catch {
146→            continue;
147→          }
148→        }
149→
150→        // Apply transform (same switch logic as for exact)
151→        switch (transform) {
152→          case "promote_to_heading":
153→            nextLines[index] = `## ${line.replace(/^#+\s*/, "")}`.trimEnd();
154→            break;
155→          case "bold_prefix_before_colon":
156→            nextLines[index] = line.replace(
157→              /^([^:\n]{1,120}:)(?!\*)/,
158→              "**$1**",
159→            );
160→            break;
161→          case "normalize_list_structure": {
162→            const trimmedLine = line.trim();
163→            if (!trimmedLine) break;
164→            nextLines[index] = /^[-*]\s/.test(trimmedLine)
165→              ? trimmedLine
166→              : `- ${trimmedLine}`;
167→            break;
168→          }
169→          case "normalize_markdown_table":
170→            if (line.includes("|")) {
171→              nextLines[index] = line
172→                .split("|")
173→                .map((cell) => cell.trim())
174→                .join(" | ")
175→                .trim();
176→            }
177→            break;
178→          case "reshape_markdown_block":
179→            nextLines[index] = line.trimEnd();
180→            break;
181→        }
182→      }
183→      continue;
184→    }
185→
186→    // All effects are now custom_style after normalization
187→    {
188→      const transform = effect.markdownTransform;
189→      if (!transform) continue;
190→
191→      if (
192→        strategy === "prefix_before_colon" &&
193→        transform === "bold_prefix_before_colon"
194→      ) {
195→        for (let index = 0; index < nextLines.length; index += 1) {
196→          const line = nextLines[index] ?? "";
197→          nextLines[index] = line.replace(/^([^:\n]{1,120}:)(?!\*)/, "**$1**");
198→        }
199→        continue;
200→      }
201→
202→      if (
203→        strategy === "markdown_table" &&
204→        transform === "normalize_markdown_table"
205→      ) {
206→        for (let index = 0; index < nextLines.length; index += 1) {
207→          const line = nextLines[index] ?? "";
208→          if (!line.includes("|")) continue;
209→          nextLines[index] = line
210→            .split("|")
211→            .map((cell) => cell.trim())
212→            .join(" | ")
213→            .trim();
214→        }
215→        continue;
216→      }
217→
218→      const lineStart = "lineStart" in selector ? selector.lineStart : null;
219→      const lineEnd = "lineEnd" in selector ? selector.lineEnd : lineStart;
220→      if (!lineStart || !lineEnd) continue;
221→      const startIndex = Math.max(0, lineStart - 1);
222→      const endIndex = Math.min(nextLines.length - 1, lineEnd - 1);
223→
224→      switch (transform) {
225→        case "promote_to_heading":
226→          nextLines[startIndex] =
227→            `## ${nextLines[startIndex]?.replace(/^#+\s*/, "") ?? ""}`.trimEnd();
228→          break;
229→        case "bold_prefix_before_colon":
230→          for (let index = startIndex; index <= endIndex; index += 1) {
231→            const line = nextLines[index] ?? "";
232→            nextLines[index] = line.replace(
233→              /^([^:\n]{1,120}:)(?!\*)/,
234→              "**$1**",
235→            );
236→          }
237→          break;
238→        case "normalize_list_structure":
239→          for (let index = startIndex; index <= endIndex; index += 1) {
240→            const line = nextLines[index] ?? "";
241→            const trimmedLine = line.trim();
242→            if (!trimmedLine) continue;
243→            nextLines[index] = /^[-*]\s/.test(trimmedLine)
244→              ? trimmedLine
245→              : `- ${trimmedLine}`;
246→          }
247→          break;
248→        case "normalize_markdown_table":
249→          for (let index = startIndex; index <= endIndex; index += 1) {
250→            const line = nextLines[index] ?? "";
251→            nextLines[index] = line
252→              .split("|")
253→              .map((cell) => cell.trim())
254→              .join(" | ")
255→              .trim();
256→          }
257→          break;
258→        case "reshape_markdown_block":
259→          for (let index = startIndex; index <= endIndex; index += 1) {
260→            nextLines[index] = (nextLines[index] ?? "").trimEnd();
261→          }
262→          break;
263→      }
264→    }
265→  }
266→
267→  return nextLines.join("\n");
268→}
