 36→
 37→export class FormatPluginRegistry {
 38→  private plugins = new Map<string, FormatPlugin>();
 39→
 40→  register(plugin: FormatPlugin): void {
 41→    if (this.plugins.has(plugin.descriptor.id)) {
 42→      throw new Error(
 43→        `Format plugin "${plugin.descriptor.id}" is already registered.`,
 44→      );
 45→    }
 46→    this.plugins.set(plugin.descriptor.id, plugin);
 47→  }
 48→
 49→  get(id: string): FormatPlugin | undefined {
 50→    return this.plugins.get(id);
 51→  }
 52→
 53→  getAll(): FormatPlugin[] {
 54→    return [...this.plugins.values()];
 55→  }
 56→}
