 59→function _describeSelectionLabel(selection: AdjustmentSelection) {
 60→  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
 61→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 62→  }
 63→
 64→  return formatMessageBlockLabel(
 65→    selection.messageRole,
 66→    selection.messageIndex + 1,
 67→    selection.blockType,
 68→  );
 69→}
