 83→export function FormatWorkspace({
 84→  activeStage,
 85→  elapsedTime,
 86→  job,
 87→  view,
 88→  onViewChange,
 89→}: FormatWorkspaceProps) {
 90→  const isAdjustableView = adjustableViews.has(view);
 91→
 92→  const session = useAdjustmentSession(view, job.id);
 93→  const rules = useFormatRules(view, job.id);
 94→  const snapshots = useSnapshots(job.id);
 95→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 96→  const resolvedMessages = useResolvedConversation(
 97→    job.conversation,
 98→    messageEdits.editedMessagesMap,
 99→  );
100→  const autoSnapshot = useAutoSnapshot({
101→    activeSnapshot: snapshots.activeSnapshot,
102→    create: snapshots.create,
103→    activate: snapshots.activate,
104→  });
105→  const deletion = useMessageDeletion(job.id);
106→  const deletionToast = useDeletionToast();
107→  const [editMode, setEditMode] = useState<EditMode>("view");
108→
109→  // Mutual exclusion: edit mode and adjustment mode must never be active simultaneously
110→  const handleEditModeChange = useCallback(
111→    (mode: EditMode) => {
112→      if (mode === "edit" && session.adjustModeEnabled) {
113→        session.toggleAdjustMode();
114→      }
115→      setEditMode(mode);
116→    },
117→    [session],
118→  );
119→
120→  const handleToggleAdjustMode = useCallback(() => {
121→    if (!session.adjustModeEnabled && editMode === "edit") {
122→      setEditMode("view");
123→    }
124→    session.toggleAdjustMode();
125→  }, [session, editMode]);
126→
127→  const hasEdits = resolvedMessages.some((m) => m.isEdited);
128→
129→  // beforeunload warning when unsaved edits exist.
130→  // hasPendingEdits covers both debounce timers that haven't fired yet and
131→  // in-flight HTTP mutations, preventing data loss during the 500 ms debounce
132→  // window where isSaving alone would still be false.
133→  useEffect(() => {
134→    if (!messageEdits.hasPendingEdits) return;
135→    const handler = (e: BeforeUnloadEvent) => {
136→      e.preventDefault();
137→    };
138→    window.addEventListener("beforeunload", handler);
139→    return () => window.removeEventListener("beforeunload", handler);
140→  }, [messageEdits.hasPendingEdits]);
141→
142→  const handleBlocksChange = useCallback(
143→    (messageId: string, blocks: Block[]) => {
144→      void autoSnapshot.ensureSnapshot().then((ready) => {
145→        if (ready) {
146→          messageEdits.saveEdit(messageId, blocks);
147→        }
148→      });
149→    },
150→    [autoSnapshot, messageEdits],
151→  );
152→  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
153→  const [deleteDialog, setDeleteDialog] = useState<{
154→    messageId: string;
155→    isRound: boolean;
156→    preview: string;
157→  } | null>(null);
158→  const popover = useAdjustmentPopover();
159→
160→  const handleDeleteMessage = useCallback(
161→    (messageId: string) => {
162→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
163→      const preview =
164→        msg?.blocks
165→          .map((b) => ("text" in b ? b.text : b.type))
166→          .join(" ")
167→          .slice(0, 200) ?? messageId;
168→      setDeleteDialog({ messageId, isRound: false, preview });
169→    },
170→    [job.conversation?.messages],
171→  );
172→
173→  const handleDeleteRound = useCallback(
174→    (messageId: string) => {
175→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
176→      const preview =
177→        msg?.blocks
178→          .map((b) => ("text" in b ? b.text : b.type))
179→          .join(" ")
180→          .slice(0, 200) ?? messageId;
181→      setDeleteDialog({ messageId, isRound: true, preview });
182→    },
183→    [job.conversation?.messages],
184→  );
185→
186→  const handleConfirmDelete = useCallback(
187→    async (reason?: string) => {
188→      if (!deleteDialog) return;
189→      const { messageId, isRound } = deleteDialog;
190→      setDeleteDialog(null);
191→      if (isRound) {
192→        const result = await deletion.deleteRound(messageId, reason);
193→        deletionToast.showDeletedToast(messageId, true, result.length);
194→      } else {
195→        await deletion.deleteMessage(messageId, reason);
196→        deletionToast.showDeletedToast(messageId, false);
197→      }
198→    },
199→    [deleteDialog, deletion, deletionToast],
200→  );
201→
202→  const handleUndoDelete = useCallback(async () => {
203→    if (!deletionToast.toast) return;
204→    await deletion.restoreMessage(deletionToast.toast.messageId);
205→    deletionToast.dismissToast();
206→  }, [deletion, deletionToast]);
207→
208→  const mergedRef = useCallback(
209→    (node: HTMLElement | null) => {
210→      (
211→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
212→      ).current = node;
213→      (
214→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
215→      ).current = node;
216→    },
217→    [session.sectionRef, popover.containerRef],
218→  );
219→
220→  const artifact =
221→    view === "reader" || view === "html-export"
222→      ? ""
223→      : (job.artifacts?.[view] ?? "Artefakt ist noch nicht verfügbar.");
224→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
225→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
226→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
227→  const displayedMarkdown = useMemo(() => {
228→    if (view !== "markdown") return artifact;
229→    try {
230→      return applyMarkdownRules(artifact, rules.activeRules);
231→    } catch {
232→      return artifact;
233→    }
234→  }, [artifact, rules.activeRules, view]);
235→
236→  const resolvedConversation = useMemo(() => {
237→    if (!job.conversation) return undefined;
238→    return {
239→      ...job.conversation,
240→      messages: resolvedMessages.map((rm) => ({
241→        id: rm.id,
242→        role: rm.role,
243→        blocks: rm.blocks,
