263→    },
264→    [resolvedConversation, view],
265→  );
266→
267→  const [copySuccess, setCopySuccess] = useState(false);
268→  const copyTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
269→
270→  const handleCopyAll = useMemo(() => {
271→    const plugin = clientFormatRegistry.get(view);
272→    if (!plugin) return undefined;
273→
274→    const doCopy = async (content: string, isHtml: boolean) => {
275→      try {
276→        if (isHtml) {
277→          const blob = new Blob([content], { type: "text/html" });
278→          const plainBlob = new Blob([content], { type: "text/plain" });
279→          await navigator.clipboard.write([
280→            new ClipboardItem({
281→              "text/html": blob,
282→              "text/plain": plainBlob,
283→            }),
284→          ]);
285→        } else {
286→          await navigator.clipboard.writeText(content);
287→        }
288→        clearTimeout(copyTimeoutRef.current);
289→        setCopySuccess(true);
290→        copyTimeoutRef.current = setTimeout(() => setCopySuccess(false), 2000);
291→      } catch {
292→        // Fallback: silently fail
293→      }
294→    };
295→
296→    // Reader & html-export: special logic with buildReaderHtml
297→    if ((view === "reader" || view === "html-export") && resolvedConversation) {
298→      return () => {
299→        const html = buildReaderHtml(
300→          resolvedConversation,
301→          readerEffectsMap,
302→          resolvedConversation.title ?? `export-${job.id}`,
303→        );
304→        void doCopy(html, true);
305→      };
306→    }
307→
308→    // Markdown: displayedMarkdown already has rules applied
309→    if (view === "markdown") {
310→      return () => {
311→        void doCopy(displayedMarkdown, false);
312→      };
313→    }
314→
315→    // Others: raw artifact
316→    if (artifact) {
