319→      };
320→    }
321→    return undefined;
322→  }, [
323→    view,
324→    displayedMarkdown,
325→    job.id,
326→    resolvedConversation,
327→    readerEffectsMap,
328→    artifact,
329→  ]);
330→
331→  const handleDownload = useMemo(() => {
332→    const plugin = clientFormatRegistry.get(view);
333→    if (!plugin) return undefined;
334→
335→    // Reader & html-export have special download logic (needs effectsMap, conversation)
336→    if ((view === "reader" || view === "html-export") && resolvedConversation) {
337→      return () => {
338→        const html = buildReaderHtml(
339→          resolvedConversation,
340→          readerEffectsMap,
341→          resolvedConversation.title ?? `export-${job.id}`,
342→        );
343→        downloadBlob(
344→          html,
345→          plugin.descriptor.exportMimeType,
346→          `export-${job.id}${plugin.descriptor.exportExtension}`,
347→        );
348→      };
349→    }
350→
351→    // For all other formats: use prepareDownload if available, else raw content
352→    const content = view === "markdown" ? displayedMarkdown : artifact;
353→    if (!content) return undefined;
354→
355→    return () => {
356→      const finalContent =
357→        plugin.prepareDownload?.(content, rules.activeRules) ?? content;
358→      downloadBlob(
359→        finalContent,
360→        plugin.descriptor.exportMimeType,
361→        `export-${job.id}${plugin.descriptor.exportExtension}`,
362→      );
363→    };
364→  }, [
365→    view,
366→    displayedMarkdown,
367→    job.id,
368→    resolvedConversation,
369→    readerEffectsMap,
370→    artifact,
371→    rules.activeRules,
372→  ]);
373→  const showPopover =
374→    session.adjustModeEnabled &&
375→    Boolean(session.activeSelection) &&
376→    Boolean(session.activeAnchor);
377→
378→  const popoverCallbacksRef = useRef({
379→    handleDiscardSession: session.handleDiscardSession,
380→    activeSessionDetail: session.activeSessionDetail,
381→    handleRejectLastChange: rules.handleRejectLastChange,
382→    setReplyVisible: session.setReplyVisible,
383→  });
384→  popoverCallbacksRef.current = {
385→    handleDiscardSession: session.handleDiscardSession,
386→    activeSessionDetail: session.activeSessionDetail,
387→    handleRejectLastChange: rules.handleRejectLastChange,
388→    setReplyVisible: session.setReplyVisible,
389→  };
390→
391→  const handlePopoverClose = useCallback(() => {
392→    popoverCallbacksRef.current.handleDiscardSession();
393→  }, []);
394→
395→  const handleRejectLastChange = useCallback(() => {
396→    const {
397→      activeSessionDetail,
398→      handleRejectLastChange: reject,
399→      setReplyVisible,
400→    } = popoverCallbacksRef.current;
401→    if (activeSessionDetail) {
402→      void reject(activeSessionDetail).then((success) => {
403→        if (success) setReplyVisible(false);
404→      });
405→    }
406→  }, []);
407→
408→  const sessionError =
409→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
410→
411→  const viewErrorFallback = (_error: Error, reset: () => void) => (
412→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
413→      <p className="text-red-700">{miscLabels.viewLoadError}</p>
414→      <button
415→        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
416→        type="button"
417→        onClick={reset}
418→      >
419→        {miscLabels.retryButton}
420→      </button>
421→    </div>
422→  );
423→
424→  return (
425→    <section
426→      ref={mergedRef}
427→      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
428→    >
429→      <StatusHeader
430→        activeStage={activeStage}
431→        elapsedTime={elapsedTime}
432→        job={job}
433→      />
434→
435→      {job.warnings.length > 0 ? (
436→        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
437→          {job.warnings[0]}
438→        </div>
439→      ) : null}
440→
441→      {job.status === "failed" ? (
442→        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
443→          <p className="font-medium">{miscLabels.importFailed}</p>
444→          {job.errorStage && job.errorStage !== "done" && (
445→            <p className="text-sm mt-1">
446→              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
447→            </p>
448→          )}
449→          {job.error && <p className="text-sm mt-1">{job.error}</p>}
450→        </div>
451→      ) : job.status === "queued" || job.status === "running" ? (
452→        <LoadingStateBlock stageDetail={activeStage?.detail} />
453→      ) : (
454→        <div className="space-y-4">
455→          <CompletedToolbar
456→            adjustModeEnabled={session.adjustModeEnabled}
457→            copySuccess={copySuccess}
458→            editMode={editMode}
459→            isAdjustableView={isAdjustableView}
460→            rules={rules}
461→            view={view}
462→            onCopyAll={handleCopyAll}
463→            onDownloadMarkdown={handleDownload}
464→            onEditModeChange={handleEditModeChange}
465→            onToggleAdjustMode={handleToggleAdjustMode}
466→            onViewChange={onViewChange}
467→            deletionsCount={deletion.deletionsCount}
468→            showDeleted={deletion.showDeleted}
469→            snapshotCount={snapshots.snapshots.length}
470→            onVersionsClick={() => setVersionsModalOpen(true)}
471→            onToggleShowDeleted={() =>
472→              deletion.setShowDeleted(!deletion.showDeleted)
473→            }
474→          />
475→
476→          {sessionError && !session.adjustModeEnabled ? (
477→            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
478→              {sessionError}
479→            </div>
480→          ) : null}
481→
482→          {view === "reader" ? (
483→            <ErrorBoundary fallback={viewErrorFallback}>
484→              <div className="space-y-2">
485→                <div className="flex justify-end">
486→                  <SaveIndicator
487→                    isSaving={messageEdits.isSaving}
