 37→function buildArtifacts(job: ImportJob): ImportArtifacts {
 38→  const conversation = job.conversation;
 39→
 40→  if (!conversation) {
 41→    const artifacts: Record<string, string> = {};
 42→    for (const gen of generatorRegistry.getAll()) {
 43→      artifacts[gen.formatId] = "";
 44→    }
 45→    return artifacts;
 46→  }
 47→
 48→  const artifacts: Record<string, string> = {};
 49→  for (const gen of generatorRegistry.getAll()) {
 50→    artifacts[gen.formatId] = gen.generate(conversation);
 51→  }
 52→  return artifacts;
 53→}
 54→
 55→function patchJob(id: string, patch: Partial<ImportJob>) {
 56→  const existing = getPersistedImport(id);
 57→  if (!existing) {
 58→    return;
 59→  }
 60→
 61→  replaceImport({
 62→    ...existing,
 63→    ...patch,
 64→    updatedAt: now(),
 65→  });
 66→}
 67→
 68→export function listImportJobs(
 69→  params?: Partial<ImportListRequest>,
 70→): ImportSummary[] {
 71→  return listImportSummaries(params);
 72→}
 73→
 74→export function getImportJob(id: string) {
 75→  return getPersistedImport(id);
 76→}
 77→
 78→export function deleteImportJob(id: string): boolean {
 79→  return deleteImport(id);
 80→}
 81→
 82→export function createImportJob(input: ImportRequest) {
 83→  const timestamp = now();
 84→  const job: ImportJob = {
 85→    id: crypto.randomUUID(),
 86→    sourceUrl: input.url,
 87→    sourcePlatform: classifySourcePlatform(input.url),
 88→    mode: input.mode,
 89→    status: "queued",
 90→    currentStage: "validate",
 91→    createdAt: timestamp,
 92→    updatedAt: timestamp,
 93→    warnings: [],
 94→  };
 95→
 96→  insertImport(job);
 97→  return job;
 98→}
 99→
100→export async function runImportJob(id: string) {
101→  const job = getPersistedImport(id);
102→  if (!job) {
103→    return;
104→  }
105→
106→  patchJob(id, {
107→    status: "running",
108→    currentStage: "validate",
109→    error: undefined,
110→  });
111→
112→  try {
113→    let timeoutHandle: ReturnType<typeof setTimeout> | undefined;
114→    const timeoutPromise = new Promise<never>((_resolve, reject) => {
115→      timeoutHandle = setTimeout(() => {
116→        reject(
117→          new Error(
118→            `Import timed out after ${IMPORT_TIMEOUT_MS / 1_000}s waiting for the share page to load.`,
119→          ),
120→        );
121→      }, IMPORT_TIMEOUT_MS);
122→    });
123→
124→    let imported: Awaited<ReturnType<typeof importSharePage>> | undefined;
125→    try {
126→      imported = await Promise.race([
127→        importSharePage(job.sourceUrl, {
128→          sourcePlatform: job.sourcePlatform,
129→          onStage: (stage) => {
130→            patchJob(id, {
131→              currentStage: stage,
132→            });
133→          },
134→        }),
135→        timeoutPromise,
136→      ]);
137→    } finally {
138→      clearTimeout(timeoutHandle);
139→    }
140→
141→    withTransaction(() => {
142→      patchJob(id, {
143→        currentStage: "render",
144→        conversation: imported.conversation,
145→        summary: {
146→          messageCount: imported.conversation.messages.length,
147→          transcriptWords: conversationWordCount(imported.conversation),
148→        },
149→        warnings: imported.warnings,
150→      });
151→
152→      saveImportSnapshot({
153→        importId: id,
154→        sourceUrl: job.sourceUrl,
155→        finalUrl: imported.snapshot.finalUrl,
156→        fetchedAt: imported.snapshot.fetchedAt,
157→        pageTitle: imported.snapshot.pageTitle,
158→        rawHtml: imported.snapshot.rawHtml,
159→        normalizedPayload: imported.snapshot.normalizedPayload,
160→        fetchMetadata: imported.snapshot.fetchMetadata,
161→      });
162→
163→      const rendered = getImportJob(id);
164→      if (!rendered) {
165→        return;
166→      }
167→
168→      patchJob(id, {
169→        status: "completed",
170→        currentStage: "done",
171→        artifacts: buildArtifacts(rendered),
172→      });
173→    });
174→  } catch (error) {
175→    const currentJob = getPersistedImport(id);
176→    patchJob(id, {
177→      status: "failed",
178→      errorStage: currentJob?.currentStage,
179→      currentStage: "done",
180→      error:
181→        error instanceof Error
182→          ? error.message
183→          : "Die Import-Pipeline ist fehlgeschlagen.",
184→    });
185→  }
186→}
