27→export class ArtifactGeneratorRegistry {
28→  private generators = new Map<string, ArtifactGenerator>();
29→
30→  register(generator: ArtifactGenerator): void {
31→    this.generators.set(generator.formatId, generator);
32→  }
33→
34→  generate(formatId: string, conversation: Conversation): string {
35→    const generator = this.generators.get(formatId);
36→    if (!generator) {
37→      throw new Error(
38→        `No artifact generator registered for format "${formatId}"`,
39→      );
40→    }
41→    return generator.generate(conversation);
42→  }
43→
44→  getAll(): ArtifactGenerator[] {
45→    return [...this.generators.values()];
