 92→export class FormatRegistry {
 93→  private formats = new Map<string, OutputFormatDescriptor>();
 94→
 95→  register(format: OutputFormatDescriptor): void {
 96→    if (this.formats.has(format.id)) {
 97→      throw new Error(`Format "${format.id}" is already registered.`);
 98→    }
 99→    this.formats.set(format.id, format);
100→  }
101→
102→  get(id: string): OutputFormatDescriptor | undefined {
103→    return this.formats.get(id);
104→  }
105→
106→  getAll(): OutputFormatDescriptor[] {
107→    return [...this.formats.values()];
108→  }
109→
110→  getAdjustable(): OutputFormatDescriptor[] {
111→    return this.getAll().filter((f) => f.adjustable);
112→  }
113→
114→  supportsRuleKind(formatId: string, ruleKind: string): boolean {
115→    const format = this.formats.get(formatId);
116→    if (!format) return false;
117→    return format.supportedRuleKinds.includes(ruleKind);
118→  }
119→}
