 25→import { SaveIndicator } from "@/components/format-workspace/save-indicator";
 26→import { StatusHeader } from "@/components/format-workspace/status-header";
 27→import {
 28→  type AdjustmentSelection,
 29→  adjustableViews,
 30→  type EditMode,
 31→  type ViewMode,
 32→} from "@/components/format-workspace/types";
 33→import { UndoToast } from "@/components/format-workspace/undo-toast";
 34→import { useAdjustmentPopover } from "@/components/format-workspace/use-adjustment-popover";
 35→import { useAdjustmentSession } from "@/components/format-workspace/use-adjustment-session";
 36→import { useAutoSnapshot } from "@/components/format-workspace/use-auto-snapshot";
 37→import { useDeletionToast } from "@/components/format-workspace/use-deletion-toast";
 38→import { useFormatRules } from "@/components/format-workspace/use-format-rules";
 39→import { useMessageDeletion } from "@/components/format-workspace/use-message-deletion";
 40→import { useMessageEdits } from "@/components/format-workspace/use-message-edits";
 41→import { useResolvedConversation } from "@/components/format-workspace/use-resolved-conversation";
 42→import { useSnapshots } from "@/components/format-workspace/use-snapshots";
 43→import { VersionsModal } from "@/components/format-workspace/versions-modal";
 44→import { clientFormatRegistry } from "@/lib/format-plugins";
 45→
 46→type ActiveStage = {
 47→  detail: string;
 48→  label: string;
 49→} | null;
 50→
 51→type FormatWorkspaceProps = {
 52→  activeStage: ActiveStage;
 53→  elapsedTime: string;
 54→  job: ImportJob;
 55→  view: ViewMode;
 56→  onViewChange: (view: ViewMode) => void;
 57→};
 58→
 59→function _describeSelectionLabel(selection: AdjustmentSelection) {
 60→  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
 61→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 62→  }
 63→
 64→  return formatMessageBlockLabel(
 65→    selection.messageRole,
 66→    selection.messageIndex + 1,
 67→    selection.blockType,
 68→  );
 69→}
 70→
 71→function downloadBlob(content: string, mimeType: string, filename: string) {
 72→  const blob = new Blob([content], { type: mimeType });
 73→  const url = URL.createObjectURL(blob);
 74→  const a = document.createElement("a");
 75→  a.href = url;
 76→  a.download = filename;
 77→  document.body.appendChild(a);
 78→  a.click();
 79→  document.body.removeChild(a);
 80→  setTimeout(() => URL.revokeObjectURL(url), 100);
 81→}
 82→
 83→export function FormatWorkspace({
 84→  activeStage,
 85→  elapsedTime,
 86→  job,
 87→  view,
 88→  onViewChange,
 89→}: FormatWorkspaceProps) {
 90→  const isAdjustableView = adjustableViews.has(view);
 91→
 92→  const session = useAdjustmentSession(view, job.id);
 93→  const rules = useFormatRules(view, job.id);
 94→  const snapshots = useSnapshots(job.id);
 95→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 96→  const resolvedMessages = useResolvedConversation(
 97→    job.conversation,
 98→    messageEdits.editedMessagesMap,
 99→  );
100→  const autoSnapshot = useAutoSnapshot({
101→    activeSnapshot: snapshots.activeSnapshot,
102→    create: snapshots.create,
103→    activate: snapshots.activate,
104→  });
105→  const deletion = useMessageDeletion(job.id);
106→  const deletionToast = useDeletionToast();
107→  const [editMode, setEditMode] = useState<EditMode>("view");
108→
109→  // Mutual exclusion: edit mode and adjustment mode must never be active simultaneously
110→  const handleEditModeChange = useCallback(
111→    (mode: EditMode) => {
112→      if (mode === "edit" && session.adjustModeEnabled) {
113→        session.toggleAdjustMode();
114→      }
115→      setEditMode(mode);
116→    },
117→    [session],
118→  );
119→
120→  const handleToggleAdjustMode = useCallback(() => {
121→    if (!session.adjustModeEnabled && editMode === "edit") {
122→      setEditMode("view");
123→    }
124→    session.toggleAdjustMode();
125→  }, [session, editMode]);
126→
127→  const hasEdits = resolvedMessages.some((m) => m.isEdited);
128→
129→  // beforeunload warning when unsaved edits exist.
130→  // hasPendingEdits covers both debounce timers that haven't fired yet and
131→  // in-flight HTTP mutations, preventing data loss during the 500 ms debounce
132→  // window where isSaving alone would still be false.
133→  useEffect(() => {
134→    if (!messageEdits.hasPendingEdits) return;
135→    const handler = (e: BeforeUnloadEvent) => {
136→      e.preventDefault();
137→    };
138→    window.addEventListener("beforeunload", handler);
139→    return () => window.removeEventListener("beforeunload", handler);
140→  }, [messageEdits.hasPendingEdits]);
141→
142→  const handleBlocksChange = useCallback(
143→    (messageId: string, blocks: Block[]) => {
144→      void autoSnapshot.ensureSnapshot().then((ready) => {
145→        if (ready) {
146→          messageEdits.saveEdit(messageId, blocks);
147→        }
148→      });
149→    },
150→    [autoSnapshot, messageEdits],
151→  );
152→  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
153→  const [deleteDialog, setDeleteDialog] = useState<{
154→    messageId: string;
155→    isRound: boolean;
156→    preview: string;
157→  } | null>(null);
158→  const popover = useAdjustmentPopover();
159→
160→  const handleDeleteMessage = useCallback(
161→    (messageId: string) => {
162→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
163→      const preview =
164→        msg?.blocks
165→          .map((b) => ("text" in b ? b.text : b.type))
166→          .join(" ")
167→          .slice(0, 200) ?? messageId;
168→      setDeleteDialog({ messageId, isRound: false, preview });
169→    },
170→    [job.conversation?.messages],
171→  );
172→
173→  const handleDeleteRound = useCallback(
174→    (messageId: string) => {
175→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
176→      const preview =
177→        msg?.blocks
178→          .map((b) => ("text" in b ? b.text : b.type))
179→          .join(" ")
180→          .slice(0, 200) ?? messageId;
181→      setDeleteDialog({ messageId, isRound: true, preview });
182→    },
183→    [job.conversation?.messages],
184→  );
185→
186→  const handleConfirmDelete = useCallback(
187→    async (reason?: string) => {
188→      if (!deleteDialog) return;
189→      const { messageId, isRound } = deleteDialog;
190→      setDeleteDialog(null);
191→      if (isRound) {
192→        const result = await deletion.deleteRound(messageId, reason);
193→        deletionToast.showDeletedToast(messageId, true, result.length);
194→      } else {
195→        await deletion.deleteMessage(messageId, reason);
196→        deletionToast.showDeletedToast(messageId, false);
197→      }
198→    },
199→    [deleteDialog, deletion, deletionToast],
200→  );
201→
202→  const handleUndoDelete = useCallback(async () => {
203→    if (!deletionToast.toast) return;
204→    await deletion.restoreMessage(deletionToast.toast.messageId);
205→    deletionToast.dismissToast();
206→  }, [deletion, deletionToast]);
207→
208→  const mergedRef = useCallback(
209→    (node: HTMLElement | null) => {
210→      (
211→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
212→      ).current = node;
213→      (
214→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
215→      ).current = node;
216→    },
217→    [session.sectionRef, popover.containerRef],
218→  );
219→
220→  const artifact =
221→    view === "reader" || view === "html-export"
222→      ? ""
223→      : (job.artifacts?.[view] ?? "Artefakt ist noch nicht verfügbar.");
224→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
225→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
226→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
227→  const displayedMarkdown = useMemo(() => {
228→    if (view !== "markdown") return artifact;
229→    try {
230→      return applyMarkdownRules(artifact, rules.activeRules);
231→    } catch {
232→      return artifact;
233→    }
234→  }, [artifact, rules.activeRules, view]);
235→
236→  const resolvedConversation = useMemo(() => {
237→    if (!job.conversation) return undefined;
238→    return {
239→      ...job.conversation,
240→      messages: resolvedMessages.map((rm) => ({
241→        id: rm.id,
242→        role: rm.role,
243→        blocks: rm.blocks,
244→      })),
245→    };
246→  }, [job.conversation, resolvedMessages]);
247→
248→  const readerEffectsMap = useMemo(
249→    () =>
250→      (view === "reader" || view === "html-export") && resolvedConversation
251→        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
252→        : new Map(),
253→    [rules.activeRules, resolvedConversation, view],
254→  );
255→
256→  const handleCopyMessage = useCallback(
257→    (messageId: string) => {
258→      const msg = resolvedConversation?.messages.find(
259→        (m) => m.id === messageId,
260→      );
261→      if (!msg) return;
262→      void copyMessageToClipboard(msg, view, msg.blocks);
263→    },
264→    [resolvedConversation, view],
265→  );
266→
267→  const [copySuccess, setCopySuccess] = useState(false);
268→  const copyTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
269→
270→  const handleCopyAll = useMemo(() => {
271→    const plugin = clientFormatRegistry.get(view);
272→    if (!plugin) return undefined;
273→
274→    const doCopy = async (content: string, isHtml: boolean) => {
275→      try {
276→        if (isHtml) {
277→          const blob = new Blob([content], { type: "text/html" });
278→          const plainBlob = new Blob([content], { type: "text/plain" });
279→          await navigator.clipboard.write([
280→            new ClipboardItem({
281→              "text/html": blob,
282→              "text/plain": plainBlob,
283→            }),
284→          ]);
285→        } else {
286→          await navigator.clipboard.writeText(content);
287→        }
288→        clearTimeout(copyTimeoutRef.current);
289→        setCopySuccess(true);
290→        copyTimeoutRef.current = setTimeout(() => setCopySuccess(false), 2000);
291→      } catch {
292→        // Fallback: silently fail
293→      }
294→    };
295→
296→    // Reader & html-export: special logic with buildReaderHtml
297→    if ((view === "reader" || view === "html-export") && resolvedConversation) {
298→      return () => {
299→        const html = buildReaderHtml(
300→          resolvedConversation,
301→          readerEffectsMap,
302→          resolvedConversation.title ?? `export-${job.id}`,
303→        );
304→        void doCopy(html, true);
305→      };
306→    }
307→
308→    // Markdown: displayedMarkdown already has rules applied
309→    if (view === "markdown") {
310→      return () => {
311→        void doCopy(displayedMarkdown, false);
312→      };
313→    }
314→
315→    // Others: raw artifact
316→    if (artifact) {
317→      return () => {
318→        void doCopy(artifact, false);
319→      };
320→    }
321→    return undefined;
322→  }, [
323→    view,
324→    displayedMarkdown,
325→    job.id,
326→    resolvedConversation,
327→    readerEffectsMap,
328→    artifact,
329→  ]);
330→
331→  const handleDownload = useMemo(() => {
332→    const plugin = clientFormatRegistry.get(view);
333→    if (!plugin) return undefined;
334→
335→    // Reader & html-export have special download logic (needs effectsMap, conversation)
336→    if ((view === "reader" || view === "html-export") && resolvedConversation) {
337→      return () => {
338→        const html = buildReaderHtml(
339→          resolvedConversation,
340→          readerEffectsMap,
341→          resolvedConversation.title ?? `export-${job.id}`,
342→        );
343→        downloadBlob(
344→          html,
345→          plugin.descriptor.exportMimeType,
346→          `export-${job.id}${plugin.descriptor.exportExtension}`,
347→        );
348→      };
349→    }
350→
351→    // For all other formats: use prepareDownload if available, else raw content
352→    const content = view === "markdown" ? displayedMarkdown : artifact;
353→    if (!content) return undefined;
354→
355→    return () => {
356→      const finalContent =
357→        plugin.prepareDownload?.(content, rules.activeRules) ?? content;
358→      downloadBlob(
359→        finalContent,
360→        plugin.descriptor.exportMimeType,
361→        `export-${job.id}${plugin.descriptor.exportExtension}`,
362→      );
363→    };
364→  }, [
365→    view,
366→    displayedMarkdown,
367→    job.id,
368→    resolvedConversation,
369→    readerEffectsMap,
370→    artifact,
371→    rules.activeRules,
372→  ]);
373→  const showPopover =
374→    session.adjustModeEnabled &&
375→    Boolean(session.activeSelection) &&
376→    Boolean(session.activeAnchor);
377→
378→  const popoverCallbacksRef = useRef({
379→    handleDiscardSession: session.handleDiscardSession,
380→    activeSessionDetail: session.activeSessionDetail,
381→    handleRejectLastChange: rules.handleRejectLastChange,
382→    setReplyVisible: session.setReplyVisible,
383→  });
384→  popoverCallbacksRef.current = {
385→    handleDiscardSession: session.handleDiscardSession,
386→    activeSessionDetail: session.activeSessionDetail,
387→    handleRejectLastChange: rules.handleRejectLastChange,
388→    setReplyVisible: session.setReplyVisible,
389→  };
390→
391→  const handlePopoverClose = useCallback(() => {
392→    popoverCallbacksRef.current.handleDiscardSession();
393→  }, []);
394→
395→  const handleRejectLastChange = useCallback(() => {
396→    const {
397→      activeSessionDetail,
398→      handleRejectLastChange: reject,
399→      setReplyVisible,
400→    } = popoverCallbacksRef.current;
401→    if (activeSessionDetail) {
402→      void reject(activeSessionDetail).then((success) => {
403→        if (success) setReplyVisible(false);
404→      });
405→    }
406→  }, []);
407→
408→  const sessionError =
409→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
410→
411→  const viewErrorFallback = (_error: Error, reset: () => void) => (
412→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
413→      <p className="text-red-700">{miscLabels.viewLoadError}</p>
414→      <button
415→        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
416→        type="button"
417→        onClick={reset}
418→      >
419→        {miscLabels.retryButton}
420→      </button>
421→    </div>
422→  );
423→
424→  return (
425→    <section
426→      ref={mergedRef}
427→      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
428→    >
429→      <StatusHeader
430→        activeStage={activeStage}
431→        elapsedTime={elapsedTime}
432→        job={job}
433→      />
434→
435→      {job.warnings.length > 0 ? (
436→        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
437→          {job.warnings[0]}
438→        </div>
439→      ) : null}
440→
441→      {job.status === "failed" ? (
442→        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
443→          <p className="font-medium">{miscLabels.importFailed}</p>
444→          {job.errorStage && job.errorStage !== "done" && (
445→            <p className="text-sm mt-1">
446→              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
447→            </p>
448→          )}
449→          {job.error && <p className="text-sm mt-1">{job.error}</p>}
450→        </div>
451→      ) : job.status === "queued" || job.status === "running" ? (
452→        <LoadingStateBlock stageDetail={activeStage?.detail} />
453→      ) : (
454→        <div className="space-y-4">
455→          <CompletedToolbar
456→            adjustModeEnabled={session.adjustModeEnabled}
457→            copySuccess={copySuccess}
458→            editMode={editMode}
459→            isAdjustableView={isAdjustableView}
460→            rules={rules}
461→            view={view}
462→            onCopyAll={handleCopyAll}
463→            onDownloadMarkdown={handleDownload}
464→            onEditModeChange={handleEditModeChange}
465→            onToggleAdjustMode={handleToggleAdjustMode}
466→            onViewChange={onViewChange}
467→            deletionsCount={deletion.deletionsCount}
468→            showDeleted={deletion.showDeleted}
469→            snapshotCount={snapshots.snapshots.length}
470→            onVersionsClick={() => setVersionsModalOpen(true)}
471→            onToggleShowDeleted={() =>
472→              deletion.setShowDeleted(!deletion.showDeleted)
473→            }
474→          />
475→
476→          {sessionError && !session.adjustModeEnabled ? (
477→            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
478→              {sessionError}
479→            </div>
480→          ) : null}
481→
482→          {view === "reader" ? (
483→            <ErrorBoundary fallback={viewErrorFallback}>
484→              <div className="space-y-2">
485→                <div className="flex justify-end">
486→                  <SaveIndicator
487→                    isSaving={messageEdits.isSaving}
488→                    hasEdits={hasEdits}
489→                  />
490→                </div>
491→                <ReaderView
492→                  activeRules={rules.activeRules}
493→                  conversation={resolvedConversation}
494→                  adjustModeEnabled={session.adjustModeEnabled}
495→                  editMode={editMode === "edit"}
496→                  effectsMap={readerEffectsMap}
497→                  highlightedRuleId={rules.hoveredRuleId}
498→                  selectedBlock={
499→                    view === "reader" ? session.activeSelection : null
500→                  }
501→                  onSelectBlock={session.handleSelectionChange}
502→                  deletedMessageIds={deletion.deletedMessageIds}
503→                  showDeleted={deletion.showDeleted}
504→                  onBlocksChange={handleBlocksChange}
505→                  onCopyMessage={handleCopyMessage}
506→                  onDeleteMessage={handleDeleteMessage}
507→                  onDeleteRound={handleDeleteRound}
508→                  onRestoreMessage={deletion.restoreMessage}
509→                />
510→              </div>
511→            </ErrorBoundary>
512→          ) : view === "markdown" ? (
513→            <ErrorBoundary fallback={viewErrorFallback}>
514→              <MarkdownView
515→                activeRules={rules.activeRules}
516→                content={displayedMarkdown}
517→                adjustModeEnabled={session.adjustModeEnabled}
518→                highlightedRuleId={rules.hoveredRuleId}
519→                selectedRange={session.activeSelection}
520→                onSelectLines={session.handleSelectionChange}
521→              />
522→            </ErrorBoundary>
523→          ) : view === "html-export" ? (
524→            <ErrorBoundary fallback={viewErrorFallback}>
525→              <HtmlExportView
526→                conversation={resolvedConversation}
527→                rules={rules.activeRules}
528→              />
529→            </ErrorBoundary>
530→          ) : (
531→            <ErrorBoundary fallback={viewErrorFallback}>
532→              <ArtifactView content={artifact} />
533→            </ErrorBoundary>
534→          )}
535→
536→          {session.showGuide ? (
537→            <AdjustmentModeGuide
538→              view={view}
539→              onDismiss={() => session.setGuideDismissed(true)}
540→            />
541→          ) : null}
542→
543→          <ErrorBoundary
544→            fallback={
545→              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
546→                {miscLabels.adjustmentLoadError}
547→              </div>
548→            }
549→          >
550→            <AdjustmentPopover
551→              anchor={session.activeAnchor ?? null}
552→              containerRef={session.sectionRef}
553→              draftMessage={session.activeDraftMessage}
554→              error={session.activeSessionError}
555→              isLoading={session.activeSessionLoading || session.isDiscarding}
556→              isSubmitting={session.isSubmitting}
557→              open={
558→                showPopover &&
559→                Boolean(session.activeSelection) &&
560→                Boolean(session.activeAnchor)
561→              }
562→              sessionDetail={session.activeSessionDetail}
563→              showReply={session.replyVisible}
564→              view={view}
565→              onClose={handlePopoverClose}
566→              onDraftMessageChange={session.handleDraftMessageChange}
567→              onRejectLastChange={handleRejectLastChange}
568→              onSubmitMessage={session.handleSubmitMessage}
569→            />
570→          </ErrorBoundary>
571→        </div>
572→      )}
573→
574→      {deleteDialog && (
575→        <DeleteMessageDialog
576→          messagePreview={deleteDialog.preview}
577→          isRound={deleteDialog.isRound}
578→          onConfirm={(reason) => {
579→            void handleConfirmDelete(reason);
580→          }}
581→          onCancel={() => setDeleteDialog(null)}
582→        />
583→      )}
584→
585→      {deletionToast.toast && (
586→        <UndoToast
587→          message={deletionToast.toast.message}
588→          onUndo={() => {
589→            void handleUndoDelete();
590→          }}
591→          onDismiss={deletionToast.dismissToast}
592→        />
593→      )}
594→
595→      <VersionsModal
596→        open={versionsModalOpen}
597→        onOpenChange={setVersionsModalOpen}
598→        snapshots={snapshots.snapshots}
599→        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
600→        onActivate={(snapshotId) => {
601→          void snapshots.activate(snapshotId);
602→        }}
603→        onDeactivate={() => {
604→          void snapshots.deactivate();
605→        }}
606→        onCreate={(label) => {
607→          void snapshots.create(label);
608→        }}
609→        onRename={(snapshotId, label) => {
610→          void snapshots.rename(snapshotId, label);
611→        }}
612→        onDelete={(snapshotId) => {
613→          void snapshots.delete(snapshotId);
614→        }}
615→      />
616→    </section>
617→  );
618→}
