    test("renders markdown view when view is markdown", async () => {
      mockRpc.rules.list.mockResolvedValue([]);

      renderWithProviders(
        <FormatWorkspace
          activeStage={null}
          elapsedTime=""
          job={createJob()}
          view="markdown"
          onViewChange={vi.fn()}
        />,
