      expect(mockGet).toHaveBeenCalledWith("reader");
    });

    test("registry is consulted for all view types", () => {
      const views = ["reader", "markdown", "handover", "json"] as const;

      for (const view of views) {
        vi.clearAllMocks();
        mockGet.mockImplementation((id: string) => {
