      expect(mockGet).toHaveBeenCalledWith("reader");
    });

    test("handleCopyAll returns undefined when plugin is not registered", () => {
      mockGet.mockReturnValue(undefined);

      renderWithProviders(
        <FormatWorkspace
          activeStage={null}
          elapsedTime=""
          job={createJob()}
          view="reader"
