        const { unmount } = renderWithProviders(
          <FormatWorkspace
            activeStage={null}
            elapsedTime=""
            job={createJob()}
            view={view}
            onViewChange={vi.fn()}
          />,
        );

        expect(mockGet).toHaveBeenCalledWith(view);
        unmount();
      }
    });
  });
});

